const expired = $input.all().map(i => i.json);
if (expired.length === 0) {
  return [{ json: { message: 'No credits expired today', count: 0 } }];
}

const summary = expired.reduce((acc, c) => {
  const key = `${c.organization_id}:${c.dimension}`;
  if (!acc[key]) acc[key] = { organization_id: c.organization_id, dimension: c.dimension, expired_count: 0, wasted_credits: 0 };
  acc[key].expired_count++;
  acc[key].wasted_credits += Number(c.credits_remaining);
  return acc;
}, {});

return [{ json: { message: `${expired.length} credit records expired`, count: expired.length, summary: Object.values(summary) } }];
